<template>
    <section class="main-content">
        <loader :is-visible="isLoading"></loader>
        <div id="divMainLeadData" v-cloak>
            <div class="row">
                <div class="col-md-12 padding-t_8">
                    <div class="theme-primary partition-full">
                        <span class="p-name text-white">{{ $t('Manage') }} {{ $t('Account') }}</span>                        
                        <span class="float-right">
                            <a href="javascript:;" class="p-action-btn text-white" title="Page Tour"
                                @click="setTourGuideSteps(0)">
                                <em class="fa fa-road" aria-hidden="true"></em>
                                <br />{{ $t('PageTour') }}
                            </a>
                        </span>
                    </div>
                </div>
            </div>
            <div class="border p-3">
                <Form ref="form" v-slot="{ valid, errors }">
                    <dynamic-form lang="en" ref="AccountForm" :buttons="buttons" :schema="FormSchema"
                        v-on:OnSubmit="onSubmit">
                    </dynamic-form>
                    <div class="row" v-if="divchkhide">
                        <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left my-2">
                            <div class="form-group">
                                <div class="float-left">
                                    <label class="form-check form-check-inline">
                                        <div class="custom-control custom-checkbox custom-control-inline">
                                            <input id="Checkbox_395455_1" type="checkbox"
                                                class="chkItems custom-control-input"
                                                v-on:change="ChkContactbox($event)">
                                            <label for="Checkbox_395455_1" class="custom-control-label"></label>
                                        </div>
                                    </label>
                                </div>
                                <div class="float-left pt-0">
                                    <span style="font-weight: 500;">{{$t('AddContact')}}</span>
                                </div>
                            </div>
                        </div>
                    </div>
                    <div class="row" v-if="IscheckContact">
                        <div class="col-lg-12 mt-4">
                            <div class="heading-border mb-2">
                                <h5 class="h5">
                                    <span>{{ $t('ContactInformation') }}</span>
                                </h5>
                            </div>
                        </div>
                        <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                            <div class="form-group">
                                <label>{{ $t('FirstName') }}:<span class="text-danger">*</span></label>
                                <Field name="FirstName" :rules="{ 'required': true }" label="First Name"
                                    v-slot="{ errors, touched, invalid }">
                                    <input type="text" v-model="txtfirstname"
                                        v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }" name="FirstName"
                                        maxlength="100">
                                    <span name="FirstName" v-if="errors[0]"
                                        class="invalid-feedback">{{ errors[0] }}</span>
                                </Field>
                            </div>
                        </div>
                        <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                            <div class="form-group">
                                <label>{{ $t('LastName') }}:<span class="text-danger">*</span></label>
                                <Field name="LastName" :rules="{ 'required': true }" label="Last Name"
                                    v-slot="{ errors }">
                                    <input type="text" v-model="txtlastname"
                                        v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }" name="LastName"
                                        maxlength="100">
                                    <span v-if="errors[0]" name="LastName" class="invalid-feedback">{{ errors[0] }}</span>
                                </Field>
                            </div>
                        </div>
                        <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                            <div class="form-group">
                                <label>{{ $t('Email') }}:<span class="text-danger">*</span></label>
                                <Field name="Email" :rules="{ 'required': true, 'email': true }" label="Email"
                                    v-slot="{ errors }">
                                    <input type="text" v-model="txtemailid" id="Emailid" name="Email"
                                        v-bind:class="{ 'form-control': true, 'is-invalid': errors[0] }">
                                    <span v-if="errors[0]" name="Email" class="invalid-feedback">{{ errors[0] }}</span>
                                </Field>
                            </div>
                        </div>
                        <div class="col-sm-12 col-md-12 float-left col-lg-6 col-xl-6">
                            <div class="form-group">
                                <label>{{ $t('Mobile') }}: </label>
                                <vue-tel-input id="txtmobile" :default-country="'us'" mode="international" @input="onInputMobilePhone"
                                    v-model="txtmobile" name="txtmobile"></vue-tel-input>
                                <span :name="txtmobile" class="invalid-feedback d-block">{{ errors[0] }}</span>
                                <span v-if="phoneError" class="invalid-feedback d-block">Enter valid number.</span>
                            </div>
                        </div>
                    </div>
                    <div class="row flex-row-reverse mt-2">
                        <div class="col-lg-6 text-right">
                            <a href="javascript:;" v-bind:class="{ disabled: false }"
                                v-on:click="SubmitData(valid, errors)" class="btn btn-success formbtn" title="Save">
                                <em class="fa fa-save pr-2"></em>{{ $t('Save') }}
                            </a>&nbsp;
                            <a href="javascript:void(0)" class="btn btn-danger" title="Cancel" @click="onCancel">
                                <em class="fa fa-close pr-2"></em>{{ $t('Cancel') }}
                            </a>
                        </div>
                        <div class="col-lg-6">
                            <div class="py-2">
                                <small class="text-danger">{{ $t('MandatoryString') }}</small>
                            </div>
                        </div>
                    </div>
                </Form>
            </div>
        </div>
    </section>
</template>
<script>
import LeadDataService from "../../../services/DataService";
import modaladdindustry from '../../../components/Common/Modal/modaladdindustry.vue'
export default {
    components: {
        modaladdindustry
    },
    data() {
        return {
            isLoading: false,
            divchkhide: false,
            IscheckContact: false,
            name: null,
            Id: null,
            dateformat: null,
            phoneError: false,
            txtfirstname: '',
            txtlastname: '',
            txtemailid: '',
            UserName:null,
            UserId:null,
            txtmobile: '',
            ApiURL: `moduleName=CRM&subModuleCode=CRM_ACCOUNTS&langCode=en`,
            AccountCode: '',
            FormSchema: [],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success save",
                    text: "<i class='fa fa-save pr-2'></i>Submit",
                    isVisible: false
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.onCancel,
                    isVisible: false,
                }
            ],
            appUrl : process.env.VUE_APP_DEFAULT_APP_URL
        }
    },
    created: function () {
        var vm = this;
        vm.UserId = vm.GetUserInfo.ID;
        vm.UserName = vm.GetUserInfo.Name;
        this.dateformat = this.GetUserInfo.DateFormat;        
        vm.accountID = this.$route.query.id ? this.$route.query.id : 0;
        vm.AccountCode = this.$route.query.AccountCode ? this.$route.query.AccountCode : '';
        var reqid = this.$route.query.id ? this.$route.query.id : 0;
        reqid = reqid == "" ? 0 : reqid;
        if (reqid == 0)
            vm.divchkhide = true;
        vm.FetchData();
    },
    methods: {
        onInputMobilePhone(phone, phoneObject, input) {
            if (phone) {
                if (phoneObject && phoneObject?.formatted.length > 0 && (!phoneObject?.valid || phoneObject?.valid == undefined)) {
                    this.phoneError = true;
                } else
                    if (phoneObject?.formatted && phoneObject?.valid) {
                        phone = phoneObject.formatted;
                        this.fieldInfo.value = phoneObject.formatted;
                        this.phoneError = false;
                    }
            }
        },
        FetchData: function () {
            var vm = this;
            vm.isLoading = true;
            var AccountID = vm.accountID == "0" ? "" : vm.accountID;
            //var otherData = [{ id: vm.$route.query.AccountId?vm.$route.query.AccountId:'', name: vm.AccountCode }];
            //var convertJson = encodeURIComponent(JSON.stringify(otherData));
            const params = `recordId=${vm.accountID}&moduleName=CRM&subModuleCode=CRM_ACCOUNTS&langCode=en`;
            LeadDataService.GetDynamicForm(params)
                .then(function (response) {
                    vm.isLoading = false;
                    if (response.data != '') {
                        var IsActive = true;
                        var Compphone = '';
                        vm.FormSchema = vm.$refs.AccountForm.ConvertCustomFieldIntoDynamicFormObj(response.data.data);
                        vm.FormSchema.forEach((group, gi) => {
                            group.Data.forEach(async (field, fi) => {
                                const urlParams = new URLSearchParams(window.location.search);
                                var IdExist = urlParams.get('id') || 0;
                                var AccType = urlParams.get('AccountCode') || "";
                                if (field.name == 'account_type') {
                                    if (vm.accountID == 0) {
                                        field.value = vm.$route.query.AccountId ? vm.$route.query.AccountId : '';
                                    }
                                    field.disabled = true;
                                }
                                if (field.name == 'account_owner') {                                    
                                    if (field.value == '') {
                                        field.value = { label: vm.UserName, value: vm.UserId }
                                    }
                                    else {
                                        if (field.config.options != null) {
                                            var obj = field.config.options.filter(x => x.value == field.value)[0];
                                            field.value = { label: obj.name, value: obj.value }
                                        } else {
                                            field.value = { label: vm.UserName, value: vm.UserId }
                                        }
                                    }
                                    field.config.onSearchChange = vm.onSearchh; 
                                    vm.onSearchh(null,field," ");
                                }
                                if (field.name == 'status_id' && field.value == '') {
                                    field.value = field.config.options.filter(x => x.name.toLowerCase() == 'active')[0].value;
                                    IsActive = field.value;
                                }
                                if (IdExist == null) {
                                    IdExist = 0;
                                }
                                if (field.name == "phone") {
                                    Compphone = field.value;
                                }
                                if (field.name == 'account_state' && field.value == '') {
                                    field.config.options = null;
                                }
                                if (field.name == 'account_country' && field.value != '') {
                                    var stateObj = group.Data.filter(x => x.name == 'account_state')[0];
                                    await vm.GetDropDownData('ACCOUNT_STATE', stateObj, field.value, 'EDIT');
                                }
                                field.config.onChange = vm.onChangeEventForFields;
                            })
                        })
                    }
                })
        },
        onChangeEventForFields: function (x, y, z) {
            let ths = this;
            var vm = this;
            if (y.name == "account_country") {
                ths.FormSchema.forEach((group, gi) => {
                    group.Data.forEach(async (field, fi) => {
                        if (field.name == 'account_state') {
                            let id = y.value;
                            await vm.GetDropDownData('ACCOUNT_STATE', field, id, null);
                        }
                    })
                })
            }
        },
        GetDropDownData: async function (type, field, id, action) {
            var vm = this;
            var url = `id=&moduleName=CRM&type=${type}&refId=${id}`;
            await LeadDataService.getDDLData(url + "&search=").then(response => {
                if (response.data.DATA != undefined) {
                    var options = response.data.DATA;
                    field.config.options = [];
                    if (action != 'EDIT') {
                        field.value = '';
                    }
                    if (type == 'ACCOUNT_STATE') {
                        options.forEach((item) => {
                            field.config.options.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                    }
                    vm.$refs.AccountForm.UpdateKeyValue();
                }
            });
        },
        onSearchh: function (e, selctedValue, search) {            
            var vm = this;
            vm.searchSelectDataa(search, vm, selctedValue);
        },
        searchSelectDataa: function (search, ths, selctedValue) {
            this.ShowSearchDataa(search, ths, selctedValue);
        },
        ShowSearchDataa: async function (search, ths, selctedValue) {            
            var vm = this;
            var appendingUrl = `id=&&moduleName=CRM&type=CRM_USERS&search=${search}&refId=`;
            selctedValue.config.options = [];
            if (typeof (selctedValue) == 'undefined') {
                selctedValue = 0;
            }
            await LeadDataService.getDDLData(appendingUrl).then(function (response) {
                if (response.data) {
                    vm.JsonObj = response.data;
                    if (vm.JsonObj != null) {
                        response.data.DATA.forEach((item) => {
                            var obj = {
                                value: item.value,
                                name: item.name
                            }
                            selctedValue.config.options.push(obj);
                        })
                        vm.$refs.AccountForm.UpdateKeyValue();
                    }
                }
            });
        },
        ChkContactbox: function (e) {
            var vm = this;
            vm.submitted = '';
            vm.IscheckContact = $(e.target).prop("checked");
            if (!vm.IscheckContact) {
                vm.txtfirstname = ''
                vm.txtlastname = '',
                    vm.txtemailid = '',
                    vm.txtmobile = ''
            }
            if (vm.IscheckContact) {
                var reqid = vm.$route.query.id ? vm.$route.query.id : 0;
                reqid = reqid == "" ? 0 : reqid;
            }
        },
        onSubmit: function () { },
        onCancel: function () {
            var vm=this;
            if(vm.$route.query.reqfrom && vm.$route.query.reqfrom.toLowerCase() == '/client/index'){
                 vm.$router.push('/Client/Index');
             }else{
                  this.$router.push({ name: 'CRMAccounts' });
             }
        },
        SubmitData(valid, errors) {
            var vm = this;
            var Cname = "";
            var adrs1 = "";
            var adrs2 = "";
            var cty = "";
            var zipc = "";
            var accname = "";
            var accowner = "";
            vm.$refs.form.validate().then((result) => {
                if (result) {
                    vm.isLoading = true;
                    var accountcontact = [];
                    var Isvalidcnt = 0;
                    var CustomFieldArray = vm.$refs.AccountForm.ConvertDynamicFormObjToCustomFieldObj(vm.FormSchema);
                    CustomFieldArray.forEach((x) => {
                        if (x.field_name == 'account_name') {
                            accname = x.field_value;
                        }
                        if (x.field_name == 'account_id') {
                            x.field_value = vm.$route.query.id ? vm.$route.query.id : 0;
                        }
                        if (x.field_name == 'account_owner') {
                            if (!vm.isBlank(x.field_value)) {
                                x.field_value = x.field_value.value;
                                accowner = x.field_value.value;
                            }
                        }
                        if (x.field_name == 'company_name') {
                            Cname = x.field_value;
                        }
                        if (x.field_name == 'account_address') {
                            adrs1 = x.field_value;
                        }
                        if (x.field_name == 'account_address2') {
                            adrs2 = x.field_value;
                        }
                        if (x.field_name == 'account_city') {
                            cty = x.field_value;
                        }
                        if (x.field_name == 'account_zip_code') {
                            zipc = x.field_value;
                        }
                    });
                    const urlParams = new URLSearchParams(window.location.search);
                    var IdExist = urlParams.get('id') || 0;
                    var AccType = urlParams.get('AccountCode') || "";
                    if (IdExist == null) {
                        IdExist = 0;
                    }
                    var stateName = $('select[name="account_state"] option:selected').text();
                    var companyaddr = Cname + " " + adrs1 + " " + adrs2 + " " + cty + " " + (stateName == "Select" ? "--" : stateName) + " " + zipc;
                    var contactaddr = vm.txtfirstname + " " + vm.txtlastname + " " + adrs1 + " " + adrs2 + " " + cty + " " + (stateName == "Select" ? "--" : stateName) + " " + zipc;
                    if (IdExist == 0 && accname == '') {
                        var newAddres = Cname != '' ? $.trim(companyaddr) : $.trim(contactaddr);
                        var previousItem = data[data.findIndex(x => x.field_name == "account_name")];
                        previousItem.field_value = newAddres;
                    }
                    if (Isvalidcnt > 0) {

                        return false;
                    }
                    var accountcontactobject = {
                        first_name: vm.txtfirstname,
                        last_name: vm.txtlastname,
                        email_id: vm.txtemailid,
                        mobile_number: vm.txtmobile
                    };
                    var postJSON = null;
                    if (vm.IscheckContact) {
                        postJSON = {
                            data: CustomFieldArray,
                            accountcontact: accountcontactobject
                        };
                    }
                    else {
                        postJSON = {
                            data: CustomFieldArray
                        };
                    }
                    var objectPostString = JSON.stringify(postJSON);
                    LeadDataService.SaveAccountInfo(objectPostString).then(function (response) {
                        vm.isLoading = false;
                        if (response.data[0].Code == "1") {
                            if (vm.accountID > 0) {
                                vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Account')]), "success", true, vm.$t("Alert"));

                            } else {
                                vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Account')]), "success", true, vm.$t("Alert"));
                            }
                            if(vm.$route.query.reqfrom && vm.$route.query.reqfrom.toLowerCase() == '/client/index'){
                                // window.location.href = vm.appUrl + '/Client/Index?reqhFrom=0';
                                vm.$router.push('/Client/Index');
                            }
                            else{
                                vm.$router.push({ name: 'CRMAccounts' });
                            }
                            
                        }

                        else if (response.data[0].Code == "2") {
                            vm.ShowAlert(vm.$t("Account name already exist"), "warning", true, vm.$t("Alert"));
                        }
                        else {
                            vm.ShowAlert(vm.$t('AddedError', [vm.$t('Account')]), "failure", true, vm.$t("Alert"));
                        }

                    });
                }
            });
        },
    }
}
</script>